import React from "react"
import PostTeaser from "./post-teaser"
import Layout from "../../../../src/gatsby-theme-flex/layout/layout"
import Pager from "../../../../src/gatsby-theme-flex/components/pager"
import PostsOverview from "../../../../src/gatsby-theme-flex/blocks/posts-overview"
import Section from "../../../../src/gatsby-theme-flex/blocks/section"
import Button from "../../../../src/gatsby-theme-flex/components/button"

export default ({
  posts,
  previousPagePath,
  nextPagePath,
  pageTitle,
  pageExcerpt,
}) => (

    <Layout pageTitle={pageTitle} pageExcerpt={pageExcerpt}>



     
      <PostsOverview        
        heading="Blog"              
      >
        {posts && posts.map(post => <PostTeaser {...post} key={post.id} />)}
        <Pager {...{ previousPagePath, nextPagePath }}></Pager>

      </PostsOverview>
     




    </Layout>



  )